-- migrations/002_create_feedback.sql
CREATE TABLE feedback (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    message_id    UUID NOT NULL REFERENCES messages(id) ON DELETE CASCADE,
    user_id       UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    rating        SMALLINT CHECK (rating IN (-1, 0, 1)),  -- -1=down, 1=up, 0=neutral/reset
    correction    TEXT,          -- user's improved version of the assistant message
    flag_category TEXT CHECK (flag_category IN ('harmful', 'incorrect', 'off_topic', 'other')),
    comment       TEXT,          -- free-text elaboration
    source        TEXT NOT NULL DEFAULT 'ui' CHECK (source IN ('ui', 'api')),
    created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    -- One feedback record per user per message (upsert on re-vote)
    CONSTRAINT feedback_message_user_unique UNIQUE (message_id, user_id)
);

CREATE INDEX idx_feedback_message_id  ON feedback (message_id);
CREATE INDEX idx_feedback_user_id     ON feedback (user_id);
CREATE INDEX idx_feedback_rating      ON feedback (rating) WHERE rating IS NOT NULL;
CREATE INDEX idx_feedback_flag        ON feedback (flag_category) WHERE flag_category IS NOT NULL;
CREATE INDEX idx_feedback_created_at  ON feedback (created_at DESC);

-- Review queue for flagged content
CREATE TABLE review_queue (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    feedback_id UUID NOT NULL REFERENCES feedback(id) ON DELETE CASCADE UNIQUE,
    status      TEXT NOT NULL DEFAULT 'pending'
                CHECK (status IN ('pending', 'reviewed', 'dismissed')),
    assigned_to UUID REFERENCES users(id),
    resolved_at TIMESTAMPTZ,
    notes       TEXT,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_review_queue_status ON review_queue (status) WHERE status = 'pending';

// components/MessageFeedback.tsx
import { useState, useCallback } from "react";

type Rating = 1 | -1 | null;

interface Props {
  messageId: string;
  apiUrl: string;
  authToken: string;
}

export function MessageFeedback({ messageId, apiUrl, authToken }: Props) {
  const [rating, setRating] = useState<Rating>(null);
  const [showComment, setShowComment] = useState(false);
  const [comment, setComment] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const submit = useCallback(async (patch: Record<string, unknown>) => {
    await fetch(`${apiUrl}/v1/feedback`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${authToken}`,
      },
      body: JSON.stringify({ message_id: messageId, ...patch }),
    });
  }, [apiUrl, authToken, messageId]);

  const handleThumb = useCallback(async (value: 1 | -1) => {
    const next = rating === value ? null : value;   // toggle off if same
    setRating(next);
    setShowComment(next === -1);
    await submit({ rating: next });
  }, [rating, submit]);

  const handleComment = useCallback(async () => {
    await submit({ rating: -1, comment });
    setSubmitted(true);
  }, [comment, submit]);

  const handleFlag = useCallback(async (category: string) => {
    await submit({ flag_category: category });
  }, [submit]);

  if (submitted) return <span className="feedback-done">Thanks for the feedback</span>;

  return (
    <div className="message-feedback">
      <button
        onClick={() => handleThumb(1)}
        aria-label="Helpful"
        aria-pressed={rating === 1}
        className={rating === 1 ? "active" : ""}
      >
        👍
      </button>
      <button
        onClick={() => handleThumb(-1)}
        aria-label="Not helpful"
        aria-pressed={rating === -1}
        className={rating === -1 ? "active" : ""}
      >
        👎
      </button>
      <button
        aria-label="Report"
        onClick={() => handleFlag("incorrect")}
      >
        ⚑
      </button>

      {showComment && (
        <div className="feedback-comment">
          <textarea
            placeholder="What went wrong? (optional)"
            value={comment}
            onChange={e => setComment(e.target.value)}
            maxLength={500}
          />
          <button onClick={handleComment}>Submit</button>
          <button onClick={() => setShowComment(false)}>Skip</button>
        </div>
      )}
    </div>
  );
}
